                  import sailpoint.tools.Util;       
                  import sailpoint.object.Custom;
                  import sailpoint.object.Filter;
                  import sailpoint.object.Identity;
				  import sailpoint.object.QueryOptions;
                  import sailpoint.api.ObjectUtil;

                  String user = "";
                  List userTypes = new ArrayList();
                  
                  if(null != identityModel){
                  user = identityModel.get("launcher");
                  }
				  boolean trustedRequester = false;
				  ObjectUtil iiqObjUtil = new ObjectUtil();
                  List workgroupMembers = new ArrayList();
                  Filter wgFilter = Filter.eq("workgroup", true);
                  Filter wgNameFilter = Filter.like("name","Trusted Requesters", Filter.MatchMode.START);
                  QueryOptions qo = new QueryOptions();
                  qo.add(wgFilter,wgNameFilter);
                  List properties = new ArrayList();
                  List trustedRequestersWGs = new ArrayList();
                  properties.add("name");
                  Iterator iter = context.search(Identity.class, qo, properties);
                  while(iter.hasNext()) {
                    Object[] workGroup = iter.next();
                    if(workGroup != null) {
                      trustedRequestersWGs.add(workGroup[0]);  
                    }        
                  }
				  Util.flushIterator(iter);
                  if(trustedRequestersWGs!=null && !trustedRequestersWGs.isEmpty()){
                    for(String trustedRequestersWGName:trustedRequestersWGs){   
                      if(Util.isNotNullOrEmpty(user)){      
                        Identity delegateWGIdentity = context.getObjectByName(Identity.class,trustedRequestersWGName);
                        Identity launcherIdentity = context.getObjectByName(Identity.class,user);
                        if(delegateWGIdentity!=null && launcherIdentity!=null){
                          if(launcherIdentity.isInWorkGroup(delegateWGIdentity)){
                            trustedRequester=true;
							break;
                          }
                        }
                      }
                    }			
                  }
                  Identity identity = context.getObjectByName(Identity.class,user);
                  Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");

                  if(custom != null && custom.get("userTypes") != null){  
                  	userTypes = custom.get("userTypes");
                  }
									Filter empTypeFilter =Filter.ignoreCase(Filter.in("type", userTypes));
                  Filter activeFilter = Filter.eq("inactive", false);    
                  Filter filter = Filter.and(empTypeFilter, activeFilter);
				  if(trustedRequester){
					field.setFilterString(filter.getExpression());		  		  
		          }

                  else if(null != identity &&  Util.isNotNullOrEmpty(identity.getStringAttribute("isContractorManager")) && identity.getStringAttribute("isContractorManager").equalsIgnoreCase("true") && !identity.getManagerStatus()){
                  Filter managerFilter = Filter.eq("contractorManager", user);
                  Filter finalFilter = Filter.and(managerFilter, filter);
                  field.setFilterString(finalFilter.getExpression());                 	
                  }
                  else{                         	
                  field.setFilterString(filter.getExpression());
                  }
				  
				  if(null!=custom){
                  //comment decache //context.decache(custom);
                  }

                  if(null!=identity){
                  //comment decache //context.decache(identity);
                  }

