                  import sailpoint.object.Field;

                  Field field = form.getField("manager");

                  Filter filter = Filter.eq("type","Employee");
                  Filter managerFilter = Filter.eq("managerStatus",true);
                  Filter inactiveFilter = Filter.eq("inactive",false);

                  Filter finalFilter = Filter.and(filter,inactiveFilter,managerFilter);

                  if (Util.isNotNullOrEmpty(contractorName)) {
                  Filter userFilter = Filter.ne("name",contractorName);
                  finalFilter = Filter.and(userFilter,finalFilter);
                  }

                  field.setFilterString(finalFilter.toString());
                  field.setSortable(true);

  
