          import java.text.SimpleDateFormat;
          import java.util.Date;

          Date dateFormat = null;
          String format = "yyyy-MM-dd";
          Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
          if(custom!=null && null != custom.get("DateFormat")){
          format = custom.get("DateFormat");
          }
          SimpleDateFormat dateFormatIIQ = new SimpleDateFormat(format);
          if(null != custom){
          //comment decache //context.decache(custom);
          }

          if(removeCtrMgr != null && "true".equalsIgnoreCase(removeCtrMgr+"")){
            String ctrexpDtFormValue = form.getField("ctrexpDt").getValue() ;
            if(ctrexpDtFormValue!=null @and !ctrexpDtFormValue.isBlank()){
            dateFormat = ctrexpDtFormValue;
            }
          }else if (contractorName != null) {
          Identity identity = context.getObjectByName(Identity.class, contractorName);
          if (identity != null && identity.getAttribute("ctrexpDt") != null @and !identity.getAttribute("ctrexpDt").isBlank()) {
          dateFormat = dateFormatIIQ.parse(identity.getAttribute("ctrexpDt"));
          //comment decache //context.decache(identity);
          }
          }
          return dateFormat;

