                  Filter inactiveFilter = Filter.eq("inactive",false);

                  Filter workgroupsFilter = Filter.like("workgroups.name","Trusted Requesters",Filter.MatchMode.START);
                  
				  Filter finalFilter = Filter.or(Filter.and(inactiveFilter,filterManager),workgroupsFilter);
				  

                  if (Util.isNotNullOrEmpty(contractorName) ) {
